--[[
  SECURE LOADER BY GÀ GAMING
  Tối ưu hóa khả năng tương thích hiển thị Menu gốc 100%
--]]

local base64_data = ""

-- Trình giải mã Base64 nội bộ hiệu suất cao
local b = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function base64_decode(data)
    data = string.gsub(data, '[^'..b..'=]', '')
    return (data:gsub('.', function(x)
        if (x == '=') then return '' end
        local r,f = '', (b:find(x)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r;
    end):gsub('%d%d%d%d%d%d%d%d', function(x)
        local c=0
        for i=1,8 do c=c+(x:sub(i,i)=='1' and 2^(8-i) or 0) end
        return string.char(c)
    end))
end

-- Thực thi trực tiếp chuỗi mã nguồn sạch lên môi trường game bằng pcall
local success, result = pcall(function()
    local raw_script = base64_decode(base64_data)
    local run_script = assert(loadstring(raw_script) or load(raw_script))
    run_script()
end)

if not success then
    warn("Quá trình nạp mã nguồn gặp lỗi tương thích: " .. tostring(result))
end
